def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    term = ((ratio - a) ** 6) / ((a + b) * 1.1 + 2)
                    priority += term * np.sin(ratio * b / (a + 2)) * np.exp(-b / (a + 3))
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 1.8
            for c in range(1, 4):
                priority += np.log(ratio + c) * np.sin(ratio * c) * c
        elif 5 < ratio <= 8:
            for d in range(1, int(np.ceil(ratio)) + 5):
                for e in range(1, d + 4):
                    val = ((ratio - d) ** 4) * np.cos(ratio * e) / (e + 1)
                    priority += np.tanh(val * 1.5) * 1.8
            priority += np.log(ratio) * 15 - np.tanh(ratio - 5) * 3.5
            if i % 2 == 0:
                priority *= np.sqrt(bin_cap + 2)
            else:
                priority /= np.log1p(bin_cap + 1.5)
        elif 3 <= ratio <= 5:
            s = 0
            for f in range(1, 15):
                s += ((ratio - 3) ** f) / (f * 1.5) * np.sin(f * np.pi * ratio / 4)
            priority = (s * np.cos(5 * ratio)) - np.log(ratio) * 8 + np.tanh(3 * (5 - ratio)) * 2.2
            if bin_cap < item * 1.4:
                priority += np.sqrt(item * bin_cap) * 3.5
            else:
                priority -= np.exp(-2 * ratio) * 3
        elif 1.2 <= ratio < 3:
            s1 = 0
            s2 = 0
            for g in range(1, 12):
                s1 += ((3 - ratio) ** g) / (g ** 2 + 1) * np.cos(g * ratio * 1.3)
            for h in range(1, 7):
                s2 += np.sin(h * ratio * i) * ((ratio - 1.2) ** h) / (h + 1)
            if bin_cap < item * 1.2:
                penalty = np.log1p(item / (bin_cap + 0.2)) * 5
            else:
                penalty = np.cos(18 * ratio) * 3
            priority = s1 + s2 + penalty + np.exp(-1.3 / (ratio + 0.1))
        elif 0.5 <= ratio < 1.2:
            s3 = 0
            for j in range(1, 18):
                s3 += ((1.2 - ratio) ** j) / (j * 3.5)
            priority = s3
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 2.5)
            for k in range(1, 8):
                priority += ((1.2 - ratio) ** k) * np.sin(k * item * 1.5) * 0.85
            if bin_cap < item * 0.9:
                priority += np.sqrt(item ** 2 + bin_cap) * 3.8
            else:
                priority -= np.exp(-0.8 * ratio) * 5.2
        elif 0.15 <= ratio < 0.5:
            s4 = 0
            for l in range(1, 14):
                s4 += ((0.5 - ratio) ** l) / (l * 2.8) * np.cos(l * ratio * 2.5)
            priority = s4 + 1.5 / (bin_cap + 4)
            if int(item * 1.7) % 3 == 0:
                priority *= 3.2
            else:
                priority /= 3.7
            if bin_cap < item * 0.35:
                priority += np.log1p(item * bin_cap) * 5.1
            else:
                priority -= np.exp(-ratio * 1.5) * 4.1
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7.5) * np.cos(item * m * 1.3)
        else:
            s5 = 0
            for n in range(1, 12):
                s5 += ((0.15 - ratio) ** n) / (n * 6) * np.sin(n * item * 1.0)
            priority = s5 + 3 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5.1
            for o in range(1, 10):
                priority += ((0.15 - ratio) ** o) / (o * 8) * np.cos(item * o * 0.85)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6.8
            priority += np.sin(ratio * i * 2) * 2.7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.2
            priority -= np.cos(ratio * i * 1.7) * 2.3
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.3) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.5) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.5) * 0.7
        if i % 5 == 0:
            priority += np.tanh(ratio * i * 0.9) * 1.2
        else:
            priority -= np.sinh(ratio * i * 0.6) * 0.9
        priorities[i] = priority
    return priorities
